// ── AUDIO ENGINE ──
const AC = new (window.AudioContext || window.webkitAudioContext)();

function _unlockAudio() { if (AC.state === 'suspended') AC.resume(); }
document.addEventListener('click', _unlockAudio, { once: true });
document.addEventListener('keydown', _unlockAudio, { once: true });

function _beep(freq, type, duration, volume, delay) {
  try {
    const o = AC.createOscillator();
    const g = AC.createGain();
    o.connect(g); g.connect(AC.destination);
    o.type = type || 'sine';
    o.frequency.setValueAtTime(freq, AC.currentTime + (delay||0));
    g.gain.setValueAtTime(volume||0.3, AC.currentTime + (delay||0));
    g.gain.exponentialRampToValueAtTime(0.001, AC.currentTime + (delay||0) + duration);
    o.start(AC.currentTime + (delay||0));
    o.stop(AC.currentTime + (delay||0) + duration + 0.05);
  } catch(e) {}
}

function _noise(duration, volume) {
  try {
    const buf = AC.createBuffer(1, AC.sampleRate * duration, AC.sampleRate);
    const d = buf.getChannelData(0);
    for (let i = 0; i < d.length; i++) d[i] = Math.random() * 2 - 1;
    const src = AC.createBufferSource();
    const g = AC.createGain();
    src.buffer = buf;
    src.connect(g); g.connect(AC.destination);
    g.gain.setValueAtTime(volume||0.1, AC.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, AC.currentTime + duration);
    src.start(); src.stop(AC.currentTime + duration + 0.05);
  } catch(e) {}
}

// ── MP3 AUDIO (Re:Zero sounds) ──
let _audioRBD_short = null;
let _audioRBD_long  = null;

(function _loadAudio() {
  const SHORT_B64 = '';
  const LONG_B64  = '';

  function b64ToArrayBuffer(b64) {
    const bin = atob(b64);
    const buf = new ArrayBuffer(bin.length);
    const view = new Uint8Array(buf);
    for (let i = 0; i < bin.length; i++) view[i] = bin.charCodeAt(i);
    return buf;
  }

  AC.decodeAudioData(b64ToArrayBuffer(SHORT_B64))
    .then(buf => { _audioRBD_short = buf; })
    .catch(() => {});

  AC.decodeAudioData(b64ToArrayBuffer(LONG_B64))
    .then(buf => { _audioRBD_long = buf; })
    .catch(() => {});
})();

let _activeSrc = null;
function _playBuffer(buffer, volume) {
  if (!buffer) return;
  try {
    _unlockAudio();
    if (_activeSrc) { try { _activeSrc.stop(); } catch(_){} _activeSrc = null; }
    const src = AC.createBufferSource();
    const g = AC.createGain();
    src.buffer = buffer;
    src.connect(g); g.connect(AC.destination);
    g.gain.setValueAtTime(volume || 0.7, AC.currentTime);
    src.onended = () => { _activeSrc = null; };
    _activeSrc = src;
    src.start();
  } catch(e) {}
}

